import { DOCUMENT } from "@angular/common";
import { HttpClient } from "@angular/common/http";
import { Component, Inject, OnInit } from "@angular/core";
import { EnvService } from "src/app/core/services/env.service";
import { Permission } from "src/app/views/Models/Permissions/Permission";
import {
  VendorForUser,
  VendorReference,
} from "src/app/views/Models/Settings/Vendor";
import { User } from "../../../Models/Permissions/User";
import { TranslateService } from "@ngx-translate/core";
import { AlertService } from "src/app/core/services/alert.service";

@Component({
  selector: "app-add-vendor-for-user",
  templateUrl: "./add-vendor-for-user.page.html",
  styleUrls: ["./add-vendor-for-user.page.scss"],
})
export class AddVendorForUserPage implements OnInit {
  showLoader: boolean = false;
  initialLoad: boolean = true;
  VendorReferences: VendorReference[] = [];
  selectedUser: User;
  VendorForUsers: VendorForUser[] = [];
  selectedPermission: VendorReference[];
  selectedAllPermissions: boolean;
  constructor(
    private env: EnvService,
    private http: HttpClient,
    public translate: TranslateService,
    public alertService: AlertService,
    @Inject(DOCUMENT) private document: Document
  ) {}

  ngOnInit() {
    this.GetVendor();
  }
  ngOnDestroy(): void {}
  GetVendor() {
    this.showLoader = true;
    this.http
      .get<VendorReference[]>(this.env.API_URL + `api/Settings/GetAllVendors`)
      .subscribe({
        next: (data) => {
          this.VendorReferences = data["VendorReferences"];
          this.showLoader = false;
        },
        error: (err) => {
          console.log(err.message);
          this.showLoader = false;
        },
      });
  }
  userSelected(user: User): void {
    this.selectedUser = user;
    this.showLoader = true;
    this.http
      .get<VendorForUser[]>(
        this.env.API_URL +
          `api/Settings/GetVendorsByUser?user_name=${user.user_name}`
      )
      .subscribe({
        next: (data) => {
          this.VendorForUsers = data;
          this.showLoader = false;
        },
        error: (err) => {
          console.log(err.message);
          this.showLoader = false;
        },
      });
  }
  DeselectUser() {
    this.selectedUser = null;
  }
  async ChangePermissions(VendorForUsers: VendorForUser[], value: number) {
    var alertText = value == 1 ? "منح" : "إلغاء";
    if (
      !(await this.alertService.SaveAlert(
        `هل تريد ${alertText} جميع الصلاحيات؟`
      ))
    ) {
      this.showLoader = false;
      return;
    }
    if (value === 1) {
      this.http
        .post<VendorForUser[]>(
          this.env.API_URL +
            `api/Settings/GetvendorsAllowForUser?vendor_code=${1}&user_name=${
              this.selectedUser.user_name
            }`,
          {}
        )
        .subscribe({
          next: (data) => {
            VendorForUsers.forEach((x) => {
              x.permission = 1;
            });
            this.showLoader = false;
          },
          error: (err) => {
            console.log(err.message);
            this.showLoader = false;
          },
        });
    } else {
      this.http
        .post<VendorForUser[]>(
          this.env.API_URL +
            `api/Settings/GetVendorsNotAllowForUser?vendor_code=${0}&user_name=${
              this.selectedUser.user_name
            }`,
          {}
        )
        .subscribe({
          next: (data) => {
            VendorForUsers.forEach((x) => {
              x.permission = 0;
            });
            this.showLoader = false;
          },
          error: (err) => {
            console.log(err.message);
            this.showLoader = false;
          },
        });
    }
  }
  ChangePermission(VendorForUser: VendorForUser, value: number): void {
    this.showLoader = true;

    if (value === 1) {
      this.http
        .post<VendorForUser[]>(
          this.env.API_URL +
            `api/Settings/GetVendorAllowForUser?vendor_code=${VendorForUser.vendor_code}&user_name=${this.selectedUser.user_name}`,
          {}
        )
        .subscribe({
          next: (data) => {
            VendorForUser.permission = 1;
            this.showLoader = false;
          },
          error: (err) => {
            console.log(err.message);
            this.showLoader = false;
          },
        });
    } else {
      this.http
        .post<VendorForUser[]>(
          this.env.API_URL +
            `api/Settings/GetVendorNotAllowForUser?vendor_code=${VendorForUser.vendor_code}&user_name=${this.selectedUser.user_name}`,
          {}
        )
        .subscribe({
          next: (data) => {
            VendorForUser.permission = 0;
            this.showLoader = false;
          },
          error: (err) => {
            console.log(err.message);
            this.showLoader = false;
          },
        });
    }
  }
  checkAllVendorEnable(VendorForUser: VendorForUser[]): boolean {
    return VendorForUser.every((item) => item.permission == 1);
  }
  checkAllVendorDisable(VendorForUser: VendorForUser[]): boolean {
    return VendorForUser.every((item) => item.permission == 0);
  }
}
